public class PlantCare {
    /**
     * This method counts the number of plants that require watering.
     * A plant requires watering if its moisture level is below a certain threshold.
     * 
     * @param moistureLevels an array of integers representing the moisture levels of plants
     * @param threshold the moisture level below which a plant needs watering
     * @return the number of plants that need watering
     */
    public static int countPlantsNeedingWater(int[] moistureLevels, int threshold) {
        int count = 0;
        for (int moisture : moistureLevels) {
            if (moisture < threshold) {
                count++;
            }
        }
        return count;
    }

    public static void main(String[] args) {
        int[] moistureLevels = {30, 15, 25, 10, 40};
        int threshold = 20;
        System.out.println("Plants needing water: " + countPlantsNeedingWater(moistureLevels, threshold));
    }
}
